// Parse Evolution API webhook payload
const body = $input.first().json.body || $input.first().json;
const event = body.event;

// Handle different Evolution events
if (event === 'messages.upsert') {
  const msg = body.data;
  const key = msg.key;
  const isFromMe = key.fromMe;

  // Skip outgoing messages (we already logged them)
  if (isFromMe) {
    return [{ json: { skip: true, reason: 'Outgoing message from this device' } }];
  }

  const phone = key.remoteJid?.replace('@s.whatsapp.net', '') || '';
  const pushName = msg.pushName || phone;

  let content = '';
  let contentType = 'text';
  let mediaUrl = null;

  if (msg.message?.conversation) {
    content = msg.message.conversation;
  } else if (msg.message?.extendedTextMessage?.text) {
    content = msg.message.extendedTextMessage.text;
  } else if (msg.message?.imageMessage) {
    content = msg.message.imageMessage.caption || '[Imagem]';
    contentType = 'image';
    mediaUrl = msg.message.imageMessage.url;
  } else if (msg.message?.audioMessage) {
    content = '[Áudio]';
    contentType = 'audio';
    mediaUrl = msg.message.audioMessage.url;
  } else if (msg.message?.videoMessage) {
    content = msg.message.videoMessage.caption || '[Vídeo]';
    contentType = 'video';
    mediaUrl = msg.message.videoMessage.url;
  } else if (msg.message?.documentMessage) {
    content = msg.message.documentMessage.fileName || '[Documento]';
    contentType = 'document';
    mediaUrl = msg.message.documentMessage.url;
  } else if (msg.message?.stickerMessage) {
    content = '[Sticker]';
    contentType = 'sticker';
  } else {
    content = '[Mensagem não suportada]';
  }

  return [{
    json: {
      event_type: 'message.received',
      whatsapp_msg_id: key.id,
      phone: phone,
      contact_name: pushName,
      direction: 'in',
      content: content,
      content_type: contentType,
      media_url: mediaUrl,
      timestamp: new Date(msg.messageTimestamp * 1000).toISOString(),
      instance: body.instance,
      raw_payload: body
    }
  }];

} else if (event === 'connection.update') {
  // Session status change (connected, disconnected, expired)
  const state = body.data?.state;
  return [{
    json: {
      event_type: 'session.status',
      instance: body.instance,
      status: state === 'open' ? 'connected' : state === 'close' ? 'disconnected' : 'expired',
      skip_message: true,
      raw_payload: body
    }
  }];

} else if (event === 'qrcode.updated') {
  return [{
    json: {
      event_type: 'qrcode.updated',
      instance: body.instance,
      qrcode: body.data?.qrcode,
      skip_message: true,
      raw_payload: body
    }
  }];

} else {
  return [{ json: { skip: true, reason: `Unhandled event: ${event}` } }];
}

// Upsert contact in Supabase
const contactResult = await $helpers.httpRequest({
  method: 'POST',
  url: `${$env.SUPABASE_URL}/rest/v1/contacts`,
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=representation'
  },
  body: JSON.stringify({
    phone: $json.phone,
    name: $json.contact_name
  })
});

const contactId = contactResult?.[0]?.id;

return [{ json: { ...$json, contact_id: contactId } }];
